"""sitecustomize.py — Auto-applied monkey-patches for the quantization pipeline.

Currently patches `huggingface_hub.try_to_load_from_cache` to validate `.no_exist/`
markers against the actual snapshot contents. This handles the case where HF's
negative cache (`<storage>/.no_exist/<commit>/<file>`) was created before a file
was added to the snapshot (e.g., when a missing `preprocessor_config.json` was
later supplied manually via blob+symlink in the cache).
"""

import os


def _patch_try_to_load_from_cache():
    try:
        import huggingface_hub
        from huggingface_hub import try_to_load_from_cache as _orig, _CACHED_NO_EXIST, constants
        from huggingface_hub.file_download import repo_folder_name
    except Exception:
        return

    def _patched(repo_id, filename, cache_dir=None, revision=None, repo_type=None):
        result = _orig(repo_id, filename, cache_dir=cache_dir, revision=revision, repo_type=repo_type)
        if result is _CACHED_NO_EXIST:
            # Negative cache says missing - verify against the actual snapshot.
            try:
                if cache_dir is None:
                    cache_dir = constants.HF_HUB_CACHE
                if revision is None:
                    revision = "main"
                if repo_type is None:
                    repo_type = "model"
                repo_cache = os.path.join(cache_dir, repo_folder_name(repo_id=repo_id, repo_type=repo_type))
                refs_dir = os.path.join(repo_cache, "refs")
                actual_revision = revision
                if os.path.isdir(refs_dir):
                    ref_file = os.path.join(refs_dir, revision)
                    if os.path.isfile(ref_file):
                        with open(ref_file) as f:
                            actual_revision = f.read().strip()
                snapshot_path = os.path.join(repo_cache, "snapshots", actual_revision, filename)
                if os.path.isfile(snapshot_path):
                    no_exist_path = os.path.join(repo_cache, ".no_exist", actual_revision, filename)
                    try:
                        if os.path.exists(no_exist_path):
                            os.remove(no_exist_path)
                    except OSError:
                        pass
                    return snapshot_path
            except Exception:
                pass
        return result

    huggingface_hub.try_to_load_from_cache = _patched
    # Also patch in the module namespace where transformers imports it from.
    try:
        from huggingface_hub import file_download
        file_download.try_to_load_from_cache = _patched
    except Exception:
        pass
    try:
        from huggingface_hub.utils import _validators  # not used directly, but keep here for safety
    except Exception:
        pass


_patch_try_to_load_from_cache()
